// ══════════ CONFIG (rama bot WhatsApp) ══════════
const CFG = {
  D360_API_KEY : '08YFTRMVRMFS5OYFDWKHST8KSED32HBP',
  D360_BASE_URL: 'https://waba-sandbox.360dialog.io/v1',
  NOMBRE_LOCAL : 'DEMO restaurante X',
  MQTT_TOPIC   : 'COCINA_DEMO',
  ADMIN_WA     : '34633437578',
  RID          : 'demo',   // id restaurante (multi-tenant futuro)
  // URL de la carta web (GitHub Pages). Ojo mayúsculas/minúsculas.
  WEB_MENU_URL : 'https://danipr20.github.io/pedidostelegram/Web/Whatsapp/Carta/',
};
return { ...$json, __cfg: CFG };

// Entrante 360dialog (Cloud API anidado o WABA v1 plano)
const body = $json.body || $json;
const val  = body?.entry?.[0]?.changes?.[0]?.value || body;
const messages = val?.messages;
if (!messages?.length) return { hasMessage: false };

const msg     = messages[0];
const contact = val?.contacts?.[0];
const waId       = msg.from;
const clientName = contact?.profile?.name || '';

let action = 'start';
if (msg.type === 'interactive') {
  const it = msg.interactive;
  if (it.type === 'button_reply')    action = it.button_reply.id;   // ok||.. / rj||..
  else if (it.type === 'list_reply') action = it.list_reply.id;
} // cualquier texto → 'start' (le mandamos la carta)

return { hasMessage: true, waId, clientName, action };

const CFG = $('Config').first().json.__cfg;
const sd  = $getWorkflowStaticData('global');
if (!sd.pedidos) sd.pedidos = {};

const action     = $json.action || 'start';
const waId       = $json.waId;
const clientName = $json.clientName || '';
const isAdmin    = waId === CFG.ADMIN_WA;
const parts = action.split('||');
const cmd   = parts[0];

function textMsg(to, body) {
  return { waPayload: { messaging_product:'whatsapp', to, type:'text', text:{ body, preview_url:false } },
           mqttTopic:null, mqttPayload:null, clientWa:null, clientNotify:null, adminWa:null, adminNotify:null };
}

// ── ADMIN acepta → imprime ──
if (isAdmin && cmd === 'ok') {
  const pid = parts[2];
  const pedido = sd.pedidos[pid];
  if (!pedido) return textMsg(CFG.ADMIN_WA, '⚠️ Pedido no encontrado o ya procesado.');
  delete sd.pedidos[pid];
  const { clienteWa, nombre, telefono, direccion, esEntrega, items, notas } = pedido;
  const SEP='================================', sub='--------------------------------';
  const entrega = esEntrega ? `Domicilio: ${direccion}` : 'Recogida en local';
  const linDir  = esEntrega ? `\nDIRECCION: ${direccion}` : '';
  const prod    = items.map(i => `  ${i.qty}x ${i.nom}`).join('\n');
  const linNotas= notas ? `\n${sub}\nNOTAS: ${notas}` : '';
  const _dig = s => String(s||'').replace(/\D/g,'');
  const _telTicket = (!telefono || _dig(telefono) === _dig(clienteWa)) ? `TELEFONO: +${clienteWa}` : `WHATSAPP: +${clienteWa}\nTELEFONO: ${telefono}`;
  const mqttPayload = `${SEP}\n#${CFG.NOMBRE_LOCAL}\n${SEP}\nENTREGA : ${entrega}${linDir}\nCLIENTE : ${nombre}\n${_telTicket}\n${sub}\n#PRODUCTOS:\n${prod}${linNotas}\n${SEP}`;
  const tiempo = esEntrega ? '🚗 Tiempo estimado: 35-45 min.' : '⏰ Listo en aprox. 15-20 min.';
  return {
    waPayload: { messaging_product:'whatsapp', to: clienteWa, type:'text',
      text:{ body:`👨‍🍳 *¡Tu pedido está confirmado!*\n\n${tiempo}\n\n¡Gracias por tu confianza! 🙌`, preview_url:false } },
    mqttTopic: CFG.MQTT_TOPIC, mqttPayload,
    clientWa:null, clientNotify:null,
    adminWa: CFG.ADMIN_WA, adminNotify:`✅ Pedido #${pid} aceptado e impreso.`
  };
}

// ── ADMIN deniega ──
if (isAdmin && cmd === 'rj') {
  const pid = parts[2];
  const pedido = sd.pedidos[pid];
  const clienteWa = pedido?.clienteWa || parts[1];
  if (pedido) delete sd.pedidos[pid];
  return {
    waPayload: { messaging_product:'whatsapp', to: clienteWa, type:'text',
      text:{ body:`⚠️ *Pedido cancelado.*\n\nEl restaurante no ha podido aceptarlo ahora mismo. Inténtalo de nuevo, por favor.`, preview_url:false } },
    mqttTopic:null, mqttPayload:null, clientWa:null, clientNotify:null,
    adminWa: CFG.ADMIN_WA, adminNotify:`❌ Pedido #${pid} denegado.`
  };
}

// ── CLIENTE: enviar enlace a la carta web ──
const url = `${CFG.WEB_MENU_URL}?wa=${encodeURIComponent(waId)}&r=${encodeURIComponent(CFG.RID)}&n=${encodeURIComponent(clientName)}`;
return {
  waPayload: {
    messaging_product:'whatsapp', to: waId, type:'interactive',
    interactive: {
      type:'cta_url',
      body:{ text:`¡Hola${clientName?` ${clientName}`:''}! 👋 Bienvenido a *${CFG.NOMBRE_LOCAL}*.\n\nPulsa el botón para ver la carta y hacer tu pedido 👇` },
      action:{ name:'cta_url', parameters:{ display_text:'🍽️ Ver carta y pedir', url } }
    }
  },
  mqttTopic:null, mqttPayload:null, clientWa:null, clientNotify:null, adminWa:null, adminNotify:null
};

const rows = $input.all().map(i => i.json);
const carta = rows.map(item => {
  const o = {};
  for (const k in item) {
    const kl = k.toLowerCase();
    if (kl === 'cat' || kl.includes('categor'))                              o.cat  = String(item[k]).trim();
    else if (kl === 'nom' || kl.includes('product') || kl.includes('nombre')) o.nom  = String(item[k]).trim();
    else if (kl === 'prec' || kl.includes('precio'))                         o.prec = parseFloat(String(item[k]).replace(',', '.')) || 0;
    else if (kl === 'desc' || kl.includes('descrip'))                        o.desc = String(item[k]).trim();
  }
  return o;
}).filter(p => p.cat && p.nom);
return carta.map(c => ({ json: c }));

// ══════════ CONFIG (rama pedido-web) ══════════
const CFG = {
  D360_API_KEY : '08YFTRMVRMFS5OYFDWKHST8KSED32HBP',
  D360_BASE_URL: 'https://waba-sandbox.360dialog.io/v1',
  NOMBRE_LOCAL : 'DEMO restaurante X',
  ADMIN_WA     : '34633437578',
};
return { ...$json, __cfg: CFG };

const CFG  = $json.__cfg;
const body = $json.body || {};
const sd   = $getWorkflowStaticData('global');
if (!sd.pedidos) sd.pedidos = {};

const wa      = String(body.wa || '');
const cliente = body.cliente || {};
const items   = Array.isArray(body.items) ? body.items : [];
const esEntrega = body.entrega === 'delivery';
const notas   = body.notas || '';
const total   = Number(body.total) || items.reduce((s,i) => s + (i.prec*i.qty), 0);

if (!wa || !items.length) {
  return { error: true, respBody: { ok:false, error:'Pedido inválido' } };
}

const pid = Date.now().toString().slice(-6);
sd.pedidos[pid] = {
  clienteWa: wa, nombre: cliente.nombre || 'Cliente', telefono: cliente.tel || wa,
  direccion: cliente.dir || '', esEntrega, items, notas, total
};

const lineas  = items.map(i => `  • ${i.qty}x ${i.nom}`).join('\n');
const entrega = esEntrega ? `🛵 Domicilio: ${cliente.dir || ''}` : '🏃 Recogida en local';
const tot     = total.toFixed(2).replace('.', ',');
const _dig = s => String(s||'').replace(/\D/g,'');
const _waF = wa ? '+'+wa : '';
const _telIn = cliente.tel || '';
const _telAdmin = (!_telIn || _dig(_telIn) === _dig(wa)) ? `📱 WhatsApp: ${_waF}` : `📱 Envía desde: ${_waF}\n📞 Contacto: ${_telIn}`;
const bodyAdmin =
  `🚨 *NUEVO PEDIDO #${pid}*\n\n` +
  `👤 ${cliente.nombre || 'Cliente'}\n${_telAdmin}\n${entrega}\n` +
  (notas ? `📝 ${notas}\n` : '') +
  `\n🛒 *Productos:*\n${lineas}\n\n💰 *Total: ${tot} €*`;

const adminPayload = {
  messaging_product:'whatsapp', to: CFG.ADMIN_WA, type:'interactive',
  interactive:{
    type:'button',
    body:{ text: bodyAdmin.substring(0, 1024) },
    action:{ buttons:[
      { type:'reply', reply:{ id:`ok||${wa}||${pid}`, title:'✅ Aceptar' } },
      { type:'reply', reply:{ id:`rj||${wa}||${pid}`, title:'❌ Denegar' } },
    ]}
  }
};

return {
  waPayload: adminPayload,
  clientWa: wa,
  clientNotify: '⏳ *¡Pedido recibido!*\n\nEl restaurante lo está revisando. Te confirmamos en un momento por aquí. 🍳',
  respBody: { ok:true, pedidoId: pid }
};
